1	import { ReactNode, useEffect, useState } from 'react';
2	import { SonarPattern } from './SonarPattern';
3	import { SlideChrome } from './SlideChrome';
4	import type { HeroVariant } from '../types/slides';
5	
6	interface SlideProps {
7	  children: ReactNode;
8	  isActive?: boolean;
9	  notes?: string;
10	  background?: string;
11	  hero?: boolean;
12	  heroVariant?: HeroVariant;
13	}
14	
15	const STAGE_WIDTH = 1920;
16	const STAGE_HEIGHT = 1080;
17	
18	function computeScale(container: HTMLElement | null): number {
19	  if (!container) return 1;
20	  const sx = container.clientWidth / STAGE_WIDTH;
21	  const sy = container.clientHeight / STAGE_HEIGHT;
22	  return Math.min(sx, sy);
23	}
24	
25	export function Slide({
26	  children,
27	  isActive = true,
28	  background,
29	  hero = false,
30	  heroVariant = 'title',
31	}: SlideProps) {
32	  const [viewportEl, setViewportEl] = useState<HTMLDivElement | null>(null);
33	  const [scale, setScale] = useState(1);
34	
35	  useEffect(() => {
36	    if (!hero || !viewportEl) return;
37	    const update = () => setScale(computeScale(viewportEl));
38	    update();
39	    const ro = new ResizeObserver(update);
40	    ro.observe(viewportEl);
41	    window.addEventListener('resize', update);
42	    window.addEventListener('orientationchange', update);
43	    return () => {
44	      ro.disconnect();
45	      window.removeEventListener('resize', update);
46	      window.removeEventListener('orientationchange', update);
47	    };
48	  }, [hero, viewportEl]);
49	
50	  if (!isActive) return null;
51	
52	  if (hero) {
53	    return (
54	      <div className="stage-viewport" ref={setViewportEl}>
55	        <SonarPattern variant={heroVariant} />
56	        <div
57	          className="stage"
58	          style={{
59	            width: `${STAGE_WIDTH}px`,
60	            height: `${STAGE_HEIGHT}px`,
61	            transform: `translate(-50%, -50%) scale(${scale})`,
62	          }}
63	        >
64	          <SlideChrome />
65	          <div className="slide slide--hero" style={background ? { background } : undefined}>
66	            {children}
67	          </div>
68	        </div>
69	      </div>
70	    );
71	  }
72	
73	  return (
74	    <div
75	      className="slide"
76	      style={background ? { background } : undefined}
77	    >
78	      {children}
